"use client";

import { useEffect, useState } from "react";
import Navbar from "@/components/Navbar";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";

export default function DetalhesSafraPage() {
  const router = useRouter();
  const params = useParams();
  const { id } = params;

  const [safra, setSafra] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [quantidadeCompra, setQuantidadeCompra] = useState(1);
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    // Verificar sessão
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }

    const fetchSafra = async () => {
      try {
        const res = await fetch(`http://localhost:5000/api/v1/safras/${id}`);
        const json = await res.json();
        if (json.success) {
          setSafra(json.data);
          setQuantidadeCompra(1); // Reset
        } else {
          router.push("/mercado"); // Safra não encontrada
        }
      } catch (error) {
        console.error("Erro ao buscar detalhes da safra", error);
      } finally {
        setLoading(false);
      }
    };

    if (id) fetchSafra();
  }, [id, router]);

  const handleComprar = async () => {
    if (!user) {
      router.push("/auth/login?redirect=/mercado/" + id);
      return;
    }

    if (user.tipo !== 'comprador') {
      alert("Apenas compradores podem realizar pedidos.");
      return;
    }

    try {
      const token = localStorage.getItem("token");
      const res = await fetch("http://localhost:5000/api/v1/comprar", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`
        },
        body: JSON.stringify({
          safra_id: safra.id,
          quantidade: quantidadeCompra
        })
      });

      const json = await res.json();
      if (json.success) {
        router.push("/dashboard"); // Sucesso, ir para dashboard ver o pedido
      } else {
        alert(json.error || "Erro ao processar compra.");
      }
    } catch (e) {
      console.error("Erro na compra", e);
      alert("Erro de conexão ao servidor.");
    }
  };

  if (loading) return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center">
      <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-700"></div>
    </div>
  );

  if (!safra) return null;

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="bg-white shadow overflow-hidden sm:rounded-lg md:flex">
          {/* Imagem do Produto */}
          <div className="md:w-1/2 bg-gray-200 relative h-64 md:h-auto">
            {safra.imagem ? (
              <img
                src={`http://localhost:5000${safra.imagem}`}
                alt={safra.produto.nome}
                className="w-full h-full object-cover"
              />
            ) : (
              <div className="flex items-center justify-center h-full text-gray-400 text-6xl">🌱</div>
            )}
          </div>

          {/* Detalhes */}
          <div className="p-8 md:w-1/2 flex flex-col justify-between">
            <div>
              <div className="flex justify-between items-start">
                <div>
                   <h1 className="text-3xl font-extrabold text-gray-900 mb-2">{safra.produto.nome}</h1>
                   <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                     {safra.produto.categoria}
                   </span>
                </div>
                <div className="text-right">
                   <p className="text-sm text-gray-500">Preço por Kg</p>
                   <p className="text-2xl font-bold text-green-600">
                     {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(safra.preco_por_unidade)}
                   </p>
                </div>
              </div>

              <div className="mt-6 border-t border-gray-200 pt-6">
                 <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider mb-3">Informações do Produtor</h3>
                 <div className="flex items-center mb-4">
                    <div className="h-10 w-10 rounded-full bg-gray-300 flex items-center justify-center text-white font-bold text-lg">
                      {safra.produtor.nome.charAt(0)}
                    </div>
                    <div className="ml-3">
                       <p className="text-sm font-medium text-gray-900">{safra.produtor.nome}</p>
                       <p className="text-xs text-gray-500">{safra.produtor.provincia}, {safra.produtor.municipio}</p>
                    </div>
                    <div className="ml-auto flex items-center">
                       <span className="text-yellow-400 text-lg mr-1">★</span>
                       <span className="font-bold text-gray-700">{safra.produtor.rating.toFixed(1)}</span>
                       <span className="ml-1 text-xs text-gray-400">({safra.produtor.vendas_concluidas} vendas)</span>
                    </div>
                 </div>

                 <div className="bg-gray-50 p-4 rounded-md text-sm text-gray-600 mb-6">
                    <p className="font-medium mb-1">Observações do Produtor:</p>
                    <p>{safra.observacoes || "Sem observações adicionais."}</p>
                 </div>
              </div>
            </div>

            {/* Área de Compra */}
            <div className="border-t border-gray-200 pt-6">
              <div className="flex justify-between items-center mb-4">
                 <label htmlFor="quantidade" className="block text-sm font-medium text-gray-700">
                    Quantidade (Kg)
                 </label>
                 <span className="text-sm text-gray-500">Disponível: {safra.quantidade_disponivel} Kg</span>
              </div>

              <div className="flex gap-4 mb-4">
                 <input
                    type="number"
                    id="quantidade"
                    min="1"
                    max={safra.quantidade_disponivel}
                    className="shadow-sm focus:ring-green-500 focus:border-green-500 block w-1/3 sm:text-sm border-gray-300 rounded-md p-2 border"
                    value={quantidadeCompra}
                    onChange={(e) => setQuantidadeCompra(Math.min(Number(e.target.value), safra.quantidade_disponivel))}
                 />
                 <div className="flex-1 flex items-center justify-end text-lg font-bold text-gray-800">
                    Total: {new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(safra.preco_por_unidade * quantidadeCompra)}
                 </div>
              </div>

              <button
                onClick={handleComprar}
                disabled={quantidadeCompra <= 0 || quantidadeCompra > safra.quantidade_disponivel}
                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 disabled:bg-gray-300 disabled:cursor-not-allowed"
              >
                Reservar Agora
              </button>
              <p className="mt-2 text-xs text-center text-gray-500">
                O pagamento só será realizado após a confirmação do produtor.
              </p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}